mapper.select:
SELECT * FROM ( SELECT inner_q.*, ROWNUM rn FROM ( SELECT rr.reservation_id AS reservationId, rr.user_account_id AS userAccountId, ad.nickname, ad.handle, ad.role_type AS roleType, rr.status, rr.pay_type AS payType, TO_CHAR(rr.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt FROM room_reservation rr JOIN vw_account_display ad ON rr.user_account_id = ad.account_id
AND ad.nickname LIKE '%' || #{nickname} || '%'
AND ad.handle LIKE '%' || #{handle} || '%'
AND rr.status = #{status}
AND rr.pay_type = #{payType}
AND rr.created_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
AND rr.created_at < TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 1
) inner_q WHERE ROWNUM <= #{offset} + #{size} ) WHERE rn > #{offset}

SELECT * FROM ( SELECT inner_q.*, ROWNUM rn FROM ( SELECT up.pass_id AS passId, up.user_account_id AS userAccountId, up.user_nickname AS nickname, up.user_handle AS handle, 'USER' AS roleType, up.status, TO_CHAR(up.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt FROM vw_user_pass up
AND up.user_nickname LIKE '%' || #{nickname} || '%'
AND up.user_handle LIKE '%' || #{handle} || '%'
AND up.status = #{status}
AND up.created_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
AND up.created_at < TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 1
) inner_q WHERE ROWNUM <= #{offset} + #{size} ) WHERE rn > #{offset}

SELECT * FROM ( SELECT inner_q.*, ROWNUM rn FROM ( SELECT p.payment_id AS paymentId, p.account_id AS accountId, ad.nickname, ad.handle, ad.role_type AS roleType, p.status, TO_CHAR(p.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt FROM payment p JOIN vw_account_display ad ON p.account_id = ad.account_id
AND ad.nickname LIKE '%' || #{nickname} || '%'
AND ad.handle LIKE '%' || #{handle} || '%'
AND p.status = #{status}
AND p.created_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
AND p.created_at < TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 1
) inner_q WHERE ROWNUM <= #{offset} + #{size} ) WHERE rn > #{offset}

SELECT TO_CHAR(p.paid_at, 'DD') AS label, NVL(SUM(p.final_amount), 0) AS amount FROM payment p JOIN vw_reservations_payment vr ON p.payment_id = vr.payment_id WHERE p.status = 'PAID' AND TO_CHAR(p.paid_at, 'YYYY-MM') = TO_CHAR(TO_DATE(#{baseDate}, 'YYYY-MM-DD'), 'YYYY-MM')
AND vr.center_name = #{centerName}
GROUP BY TO_CHAR(p.paid_at, 'DD') ORDER BY label

SELECT TO_CHAR(p.paid_at, 'MM') AS label, NVL(SUM(p.final_amount), 0) AS amount FROM payment p JOIN vw_reservations_payment vr ON p.payment_id = vr.payment_id WHERE p.status = 'PAID' AND TO_CHAR(p.paid_at, 'YYYY') = TO_CHAR(TO_DATE(#{baseDate}, 'YYYY-MM-DD'), 'YYYY')
AND vr.center_name = #{centerName}
GROUP BY TO_CHAR(p.paid_at, 'MM') ORDER BY label

SELECT 'Q' || TO_CHAR(p.paid_at, 'Q') AS label, NVL(SUM(p.final_amount), 0) AS amount FROM payment p JOIN vw_reservations_payment vr ON p.payment_id = vr.payment_id WHERE p.status = 'PAID' AND TO_CHAR(p.paid_at, 'YYYY') = TO_CHAR(TO_DATE(#{baseDate}, 'YYYY-MM-DD'), 'YYYY')
AND vr.center_name = #{centerName}
GROUP BY TO_CHAR(p.paid_at, 'Q') ORDER BY label

SELECT TO_CHAR(p.paid_at, 'YYYY') AS label, NVL(SUM(p.final_amount), 0) AS amount FROM payment p JOIN vw_reservations_payment vr ON p.payment_id = vr.payment_id WHERE p.status = 'PAID'
AND vr.center_name = #{centerName}
GROUP BY TO_CHAR(p.paid_at, 'YYYY') ORDER BY label
